mapper.select:
SELECT COUNT(1)
FROM workflow_template
WHERE page_code = #{pageCode}
AND enabled = #{enabled}

  AND (name ILIKE CONCAT('%', #{keyword}, '%') OR template_code ILIKE CONCAT('%', #{keyword}, '%'))

SELECT id, page_code, template_code, name, config_json, enabled, is_default, updated_at
FROM workflow_template
WHERE page_code = #{pageCode}
AND enabled = #{enabled}

  AND (name ILIKE CONCAT('%', #{keyword}, '%') OR template_code ILIKE CONCAT('%', #{keyword}, '%'))

ORDER BY is_default DESC, updated_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE workflow_template
SET is_default = #{isDefault}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM workflow_task
WHERE page_code = #{pageCode}
  AND template_code = #{templateCode}
  AND status = 'pending'

SELECT COUNT(1)
FROM workflow_task
WHERE record_id = #{recordId}
  AND page_code = #{pageCode}
  AND status = 'pending'

SELECT id
FROM workflow_task
WHERE instance_id = #{instanceId}
  AND node_code = #{nodeCode}
  AND status = 'pending'
ORDER BY id

SELECT id
FROM workflow_task
WHERE instance_id = #{instanceId}
  AND node_code = #{nodeCode}
  AND status = 'pending'
  AND assignee = #{assignee}
ORDER BY id
LIMIT 1

SELECT node_code
FROM workflow_task
WHERE id = #{id}

SELECT COUNT(1)
FROM workflow_task
WHERE instance_id = #{instanceId}
  AND node_code = #{nodeCode}
  AND status = 'pending'

SELECT t.id AS task_id, t.instance_id, wi.record_id, wi.page_code, wi.template_code, wt.name AS template_name, t.node_code, t.assignee, t.status AS task_status, t.action, t.comment, t.created_at AS task_created_at, t.updated_at AS task_updated_at, wi.status AS workflow_status, wi.current_node_code, wi.starter, wi.started_at, wi.finished_at FROM workflow_task t JOIN workflow_instance wi ON wi.id = t.instance_id LEFT JOIN workflow_template wt ON wt.id = wi.template_id WHERE t.status = 'pending' AND t.assignee = #{assignee} AND wi.page_code = #{pageCode}
AND ( CAST(wi.record_id AS TEXT) ILIKE CONCAT('%', #{keywords}, '%') OR COALESCE(wt.name, '') ILIKE CONCAT('%', #{keywords}, '%') OR t.node_code ILIKE CONCAT('%', #{keywords}, '%') )
ORDER BY t.created_at DESC, t.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT t.id AS task_id, t.instance_id, wi.record_id, wi.page_code, wi.template_code, wt.name AS template_name, t.node_code, t.assignee, t.status AS task_status, t.action, t.comment, t.operated_by, t.created_at AS task_created_at, t.updated_at AS task_updated_at, wi.status AS workflow_status, wi.current_node_code, wi.starter, wi.started_at, wi.finished_at FROM workflow_task t JOIN workflow_instance wi ON wi.id = t.instance_id LEFT JOIN workflow_template wt ON wt.id = wi.template_id WHERE t.status = 'done' AND t.action IN ('approve', 'reject') AND t.operated_by = #{operator} AND wi.page_code = #{pageCode}
AND ( CAST(wi.record_id AS TEXT) ILIKE CONCAT('%', #{keywords}, '%') OR COALESCE(wt.name, '') ILIKE CONCAT('%', #{keywords}, '%') OR t.node_code ILIKE CONCAT('%', #{keywords}, '%') )
ORDER BY t.updated_at DESC, t.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM workflow_instance wi
LEFT JOIN workflow_template wt ON wt.id = wi.template_id
WHERE wi.starter = #{operator}
AND wi.page_code = #{pageCode}
AND wi.status = #{status}

  AND (
    CAST(wi.record_id AS TEXT) ILIKE CONCAT('%', #{keywords}, '%')
    OR COALESCE(wt.name, '') ILIKE CONCAT('%', #{keywords}, '%')
    OR COALESCE(wi.current_node_code, '') ILIKE CONCAT('%', #{keywords}, '%')
  )

SELECT wi.id AS instance_id, wi.record_id, wi.page_code, wi.status AS workflow_status, wi.template_code, wt.name AS template_name, wi.current_node_code, p.pending_assignees, wi.starter, wi.started_at, wi.finished_at, wi.updated_at FROM workflow_instance wi LEFT JOIN workflow_template wt ON wt.id = wi.template_id LEFT JOIN LATERAL ( SELECT string_agg(t.assignee, ',' ORDER BY t.id) AS pending_assignees FROM workflow_task t WHERE t.instance_id = wi.id AND t.status = 'pending' AND t.node_code = wi.current_node_code ) p ON TRUE WHERE wi.starter = #{operator} AND wi.page_code = #{pageCode} AND wi.status = #{status}
AND ( CAST(wi.record_id AS TEXT) ILIKE CONCAT('%', #{keywords}, '%') OR COALESCE(wt.name, '') ILIKE CONCAT('%', #{keywords}, '%') OR COALESCE(wi.current_node_code, '') ILIKE CONCAT('%', #{keywords}, '%') )
ORDER BY wi.updated_at DESC, wi.id DESC LIMIT #{limit} OFFSET #{offset}
